# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os

# Database settings
rds_host = os.environ['RDS_HOST']
username = os.environ['RDS_USERNAME']
password = os.environ['RDS_PASSWORD']
database_name = os.environ['RDS_DATABASE']

def lambda_handler(event, context):
    # Connect to the database
    connection = pymysql.connect(host=rds_host, user=username, password=password, database=database_name)
    
    # Extract search parameters from the event
    search_params = event.get('queryStringParameters', {})
    query_conditions = []
    query_values = []

    # Build query dynamically based on input parameters
    if 'name' in search_params:
        query_conditions.append("name LIKE %s")
        query_values.append(f"%{search_params['name']}%")
    if 'category' in search_params:
        query_conditions.append("category = %s")
        query_values.append(search_params['category'])
    if 'price_min' in search_params:
        query_conditions.append("price >= %s")
        query_values.append(float(search_params['price_min']))
    if 'price_max' in search_params:
        query_conditions.append("price <= %s")
        query_values.append(float(search_params['price_max']))

    where_clause = " AND ".join(query_conditions) if query_conditions else "1"
    sql_query = f"SELECT * FROM products WHERE {where_clause}"

    try:
        with connection.cursor() as cursor:
            cursor.execute(sql_query, query_values)
            results = cursor.fetchall()
            columns = [desc[0] for desc in cursor.description]
            products = [dict(zip(columns, row)) for row in results]

        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

    finally:
        connection.close()